const users = $('Fetch Active PRO and INFINITY_PLUS Users').all();
const biddings = $('Fetch New Biddings Last 24h').all();

const emails = users.map(userItem => {
  const user = userItem.json;
  const today = new Date().toLocaleDateString('pt-BR', { weekday: 'long', year: 'numeric', month: 'long', day: 'numeric' });

  const biddingRows = biddings.map(b => {
    const bid = b.json;
    const value = bid.estimatedValue
      ? new Intl.NumberFormat('pt-BR', { style: 'currency', currency: 'BRL' }).format(bid.estimatedValue)
      : 'A definir';
    const openDate = bid.openingDate
      ? new Date(bid.openingDate).toLocaleDateString('pt-BR')
      : 'Não informado';
    const pdfLink = bid.pdfUrl ? `<a href="${bid.pdfUrl}" style="color:#00E5FF">Ver edital</a>` : 'N/D';

    return `
      <tr>
        <td style="padding:8px;border-bottom:1px solid #1a2035;color:#e2e8f0">${bid.title}</td>
        <td style="padding:8px;border-bottom:1px solid #1a2035;color:#94a3b8">${bid.organ}</td>
        <td style="padding:8px;border-bottom:1px solid #1a2035;color:#94a3b8">${bid.state || '-'}/${bid.city || '-'}</td>
        <td style="padding:8px;border-bottom:1px solid #1a2035;color:#00E5FF">${value}</td>
        <td style="padding:8px;border-bottom:1px solid #1a2035;color:#94a3b8">${openDate}</td>
        <td style="padding:8px;border-bottom:1px solid #1a2035">${pdfLink}</td>
      </tr>
    `;
  }).join('');

  const html = `
    <!DOCTYPE html>
    <html>
    <head><meta charset="UTF-8"></head>
    <body style="background:#0a0f1e;font-family:Arial,sans-serif;margin:0;padding:20px">
      <div style="max-width:800px;margin:0 auto;background:#0d1526;border:1px solid #1a2035;border-radius:12px;padding:24px">
        <h1 style="color:#00E5FF;margin-top:0">Performance Pregão</h1>
        <h2 style="color:#e2e8f0">Novas Licitações — ${today}</h2>
        <p style="color:#94a3b8">Olá, ${user.name || user.email}! Encontramos ${biddings.length} nova(s) licitação(ões) nas últimas 24 horas.</p>
        <table width="100%" style="border-collapse:collapse;margin-top:16px">
          <thead>
            <tr style="background:#1a2035">
              <th style="padding:8px;text-align:left;color:#00E5FF">Título</th>
              <th style="padding:8px;text-align:left;color:#00E5FF">Órgão</th>
              <th style="padding:8px;text-align:left;color:#00E5FF">Local</th>
              <th style="padding:8px;text-align:left;color:#00E5FF">Valor Est.</th>
              <th style="padding:8px;text-align:left;color:#00E5FF">Abertura</th>
              <th style="padding:8px;text-align:left;color:#00E5FF">Link</th>
            </tr>
          </thead>
          <tbody>
            ${biddingRows}
          </tbody>
        </table>
        <p style="color:#64748b;font-size:12px;margin-top:24px">Performance Pregão — Para cancelar alertas acesse sua conta em <a href="https://performancepregao.com.br" style="color:#00E5FF">performancepregao.com.br</a></p>
      </div>
    </body>
    </html>
  `;

  return {
    json: {
      to: user.email,
      subject: `[Performance Pregão] ${biddings.length} nova(s) licitação(ões) hoje — ${new Date().toLocaleDateString('pt-BR')}`,
      html
    }
  };
});

return emails;
